parameters.functionCode:
// Build HTML email content from trending data
const brands = $node['Get Trending Brands from API'].json.data;
const products = $node['Get Trending Products from API'].json.data;

let brandsList = '';
brands.forEach(brand => {
  brandsList += `<li>${brand.name} - ${brand.mentions} mentions this week</li>`;
});

let productsList = '';
products.forEach(product => {
  productsList += `
    <div style="border: 1px solid #ddd; padding: 15px; margin: 10px 0; border-radius: 4px;">
      <h4>${product.name}</h4>
      <p><strong>Brand:</strong> ${product.brand}</p>
      <p><strong>Trending Score:</strong> ${product.trend_score}/100</p>
      <p>${product.description}</p>
      <a href="https://rosier.app/product/${product.id}" style="background-color: #C4A77D; color: white; padding: 8px 16px; text-decoration: none; border-radius: 4px; display: inline-block;">View on Rosier</a>
    </div>
  `;
});

const emailContent = `
<h2>This Week's Trending Finds</h2>
<p>Here are the brands and products trending on Rosier this week:</p>

<h3>Top Brands</h3>
<ul>${brandsList}</ul>

<h3>Top Products</h3>
${productsList}

<p style="margin-top: 30px; color: #666; font-size: 12px;">
  Not interested in these trends? Update your preferences in your Rosier settings.
</p>
`;

return { emailContent, productCount: products.length, brandCount: brands.length };

